const{createApp}=Vue;const{createRouter,createWebHistory}=VueRouter;function showAlert(message,type='info'){const alertDiv=document.createElement('div');alertDiv.className=`alert alert-${type}alert-dismissible fade show position-fixed top-0 start-50 translate-middle-x mt-3`;alertDiv.style.zIndex='9999';alertDiv.innerHTML=`${message}<button type="button"class="btn-close"data-bs-dismiss="alert"></button>`;document.body.appendChild(alertDiv);setTimeout(()=>alertDiv.remove(),4000);}
const clientCache={async getOrFetch(cacheKey,fetchFn,ttlSeconds=1800){const cached=this.getFromCache(cacheKey);if(cached){console.log(`✅ Cache hit:${cacheKey}`);return cached;}console.log(`📥 Cache miss:${cacheKey},fetching from server`);const data=await fetchFn();this.setCache(cacheKey,data,ttlSeconds);return data;},getFromCache(cacheKey){try{const item=localStorage.getItem(cacheKey);if(!item)return null;const{data,expiry}=JSON.parse(item);if(Date.now()>expiry){localStorage.removeItem(cacheKey);return null;}return data;}catch(e){console.warn(`Cache read error for ${cacheKey}:`,e);return null;}},setCache(cacheKey,data,ttlSeconds=1800){try{const expiry=Date.now()+(ttlSeconds*1000);localStorage.setItem(cacheKey,JSON.stringify({data,expiry}));console.log(`💾 Cached:${cacheKey}(TTL:${ttlSeconds}s)`);}catch(e){console.warn(`Cache write error for ${cacheKey}:`,e);}},clearCache(cacheKey){localStorage.removeItem(cacheKey);console.log(`🗑️ Cache cleared:${cacheKey}`);},clearAllCache(){const keys=Object.keys(localStorage).filter(k=>k.startsWith('cinema_'));keys.forEach(k=>localStorage.removeItem(k));console.log(`🗑️ All caches cleared(${keys.length}entries)`);}};function starsDisplay(rating){return'⭐'.repeat(Math.round(rating));}
function formatDate(isoString){const date=new Date(isoString);return date.toLocaleString('uk-UA',{day:'2-digit',month:'2-digit',year:'numeric',hour:'2-digit',minute:'2-digit'});}function formatDateShort(isoString){const date=new Date(isoString);return date.toLocaleString('uk-UA',{day:'2-digit',month:'2-digit',year:'numeric'});}function formatDateTime(dateString){const date=new Date(dateString.replace(' ','T'));if(isNaN(date.getTime()))return dateString;return date.toLocaleString('uk-UA',{day:'numeric',month:'long',year:'numeric',hour:'2-digit',minute:'2-digit'});}function formatMoney(value){const num=Number(value||0);return num.toLocaleString('uk-UA',{minimumFractionDigits:0,maximumFractionDigits:2});}
const authState={authenticated:false,user:null,async check(){try{const res=await fetch('/api/auth/status');const data=await res.json();this.authenticated=data.authenticated;this.user=data.user;}catch(e){this.authenticated=false;this.user=null;}this.updateNavbar();return this.authenticated;},setUser(user){this.authenticated=true;this.user=user;this.updateNavbar();},clear(){this.authenticated=false;this.user=null;this.updateNavbar();},updateNavbar(){document.querySelectorAll('.spa-auth-only').forEach(el=>{el.style.display=this.authenticated?'':'none';});document.querySelectorAll('.spa-guest-only').forEach(el=>{el.style.display=this.authenticated?'none':'';});document.querySelectorAll('.spa-admin-only').forEach(el=>{el.style.display=(this.authenticated&&this.user?.is_admin)?'':'none';});}};

